const projects = [{
  name: 'Example',
  link: '#',
  imageURL: '../assets/myman.png',
  description: 'Lorem ipsum dolor sit amet, qui minim labore adipisicing minim sint cillum sint consectetur cupidatat.'
}];

function Project({ name, link, imageURL, description }) {
  return (
    <a href={link} className='text-lg font-[DrukWide]'> {name} </a>
  );
}

function Projects() {
  const projectItems = projects.map(project => 
  <Project name={project.name} 
    link={project.link} 
    imageURL={project.imageURL} 
    description={project.description}/>
  );

  return (
    <>
      <h1 className='text-2xl text-center text-stone-200 font-[DrukWide]'>
        Recent Projects
      </h1>
      <ul>
        { projectItems }
      </ul> 
    </>
  );
}

export default Projects;
